const items = $input.all();

// If no rows returned or reply_text is empty = cache miss
if (items.length === 0 || !items[0].json.reply_text) {
  return [{
    json: {
      cache_hit: false,
      reply_text: null,
      image_urls: null
    }
  }];
}

// Cache hit — data is directly in items[0].json, not items[0].json[0]
return [{
  json: {
    cache_hit: true,
    reply_text: items[0].json.reply_text,
    image_urls: items[0].json.image_urls
  }
}];

let imageUrls = [];
try {
  const rawUrls = $('Parse Cache Result').item.json.image_urls;
  imageUrls = JSON.parse(rawUrls || '[]');
} catch(e) {
  imageUrls = [];
}

const replyText = $('Parse Cache Result').item.json.reply_text;

return [{
  json: {
    reply_text: replyText,
    image_urls: imageUrls,
    session_id: $('Webhook').first().json.body.session_id,
    is_cached: true,
    from_cache: true 
  }
}];

// Get all rows from the SQL node and reverse them so the oldest is first
const rows = $input.all().reverse();
let historyText = "";

// Loop through each row and format it
for (const row of rows) {
  // Safe navigation to check if data exists
  if (row.json) {
    historyText += `User: ${row.json.User_Message}\n`;
    historyText += `AI: ${row.json.AI_Response}\n\n`;
  }
}

// Pass a single item forward containing the bundled text
return [{ json: { formatted_history: historyText } }];

